 111→//------------------------------------------------------------
 112→// Turns a segment into a fully charged up fuel center...
 113→void fuelcen_create(segment* segp)
 114→{
 115→	segment2* seg2p = &Segment2s[segp - Segments];
 116→
 117→	int	station_type;
 118→
 119→	station_type = seg2p->special;
 120→
 121→	switch (station_type) {
 122→	case SEGMENT_IS_NOTHING:
 123→	case SEGMENT_IS_GOAL_BLUE:
 124→	case SEGMENT_IS_GOAL_RED:
 125→		return;
 126→	case SEGMENT_IS_FUELCEN:
 127→	case SEGMENT_IS_REPAIRCEN:
 128→	case SEGMENT_IS_CONTROLCEN:
 129→	case SEGMENT_IS_ROBOTMAKER:
 130→		break;
 131→	default:
 132→		Error("Invalid station type %d in fuelcen.c\n", station_type);
 133→	}
 134→
 135→	Assert((seg2p != NULL));
 136→	if (seg2p == NULL) return;
 137→
 138→	Assert(Num_fuelcenters < MAX_NUM_FUELCENS);
 139→	Assert(Num_fuelcenters > -1);
 140→
 141→	seg2p->value = Num_fuelcenters;
 142→	Station[Num_fuelcenters].Type = station_type;
 143→	Station[Num_fuelcenters].MaxCapacity = Fuelcen_max_amount;
 144→	Station[Num_fuelcenters].Capacity = Station[Num_fuelcenters].MaxCapacity;
 145→	Station[Num_fuelcenters].segnum = seg2p - Segment2s;
 146→	Station[Num_fuelcenters].Timer = -1;
 147→	Station[Num_fuelcenters].Flag = 0;
 148→	//	Station[Num_fuelcenters].NextRobotType = -1;
 149→	//	Station[Num_fuelcenters].last_created_obj=NULL;
 150→	//	Station[Num_fuelcenters].last_created_sig = -1;
 151→	compute_segment_center(&Station[Num_fuelcenters].Center, segp);
 152→
 153→	//	if (station_type == SEGMENT_IS_ROBOTMAKER)
 154→	//		Station[Num_fuelcenters].Capacity = i2f(Difficulty_level + 3);
 155→
 156→		//mprintf( (0, "Segment %d is assigned to be fuel center %d.\n", Station[Num_fuelcenters].segnum, Num_fuelcenters ));
 157→	Num_fuelcenters++;
 158→}
