 160→//------------------------------------------------------------
 161→// Adds a matcen that already is a special type into the Station array.
 162→// This function is separate from other fuelcens because we don't want values reset.
 163→void matcen_create(segment* segp)
 164→{
 165→	segment2* seg2p = &Segment2s[segp - Segments];
 166→
 167→	int	station_type = seg2p->special;
 168→
 169→	Assert((seg2p != NULL));
 170→	Assert(station_type == SEGMENT_IS_ROBOTMAKER);
 171→	if (seg2p == NULL) return;
 172→
 173→	Assert(Num_fuelcenters < MAX_NUM_FUELCENS);
 174→	Assert(Num_fuelcenters > -1);
 175→
 176→	seg2p->value = Num_fuelcenters;
 177→	Station[Num_fuelcenters].Type = station_type;
 178→	Station[Num_fuelcenters].Capacity = i2f(Difficulty_level + 3);
 179→	Station[Num_fuelcenters].MaxCapacity = Station[Num_fuelcenters].Capacity;
 180→
 181→	Station[Num_fuelcenters].segnum = seg2p - Segment2s;
 182→	Station[Num_fuelcenters].Timer = -1;
 183→	Station[Num_fuelcenters].Flag = 0;
 184→	//	Station[Num_fuelcenters].NextRobotType = -1;
 185→	//	Station[Num_fuelcenters].last_created_obj=NULL;
 186→	//	Station[Num_fuelcenters].last_created_sig = -1;
 187→	compute_segment_center(&Station[Num_fuelcenters].Center, &Segments[seg2p - Segment2s]);
 188→
 189→	seg2p->matcen_num = Num_robot_centers;
 190→	Num_robot_centers++;
 191→
 192→	RobotCenters[seg2p->matcen_num].hit_points = MATCEN_HP_DEFAULT;
 193→	RobotCenters[seg2p->matcen_num].interval = MATCEN_INTERVAL_DEFAULT;
 194→	RobotCenters[seg2p->matcen_num].segnum = seg2p - Segment2s;
 195→	RobotCenters[seg2p->matcen_num].fuelcen_num = Num_fuelcenters;
 196→
 197→	//mprintf( (0, "Segment %d is assigned to be fuel center %d.\n", Station[Num_fuelcenters].segnum, Num_fuelcenters ));
 198→	Num_fuelcenters++;
 199→}
