 203→void fuelcen_activate(segment* segp, int station_type)
 204→{
 205→	segment2* seg2p = &Segment2s[segp - Segments];
 206→
 207→	seg2p->special = station_type;
 208→
 209→	if (seg2p->special == SEGMENT_IS_ROBOTMAKER)
 210→		matcen_create(segp);
 211→	else
 212→		fuelcen_create(segp);
 213→
 214→}
