 216→//	The lower this number is, the more quickly the center can be re-triggered.
 217→//	If it's too low, it can mean all the robots won't be put out, but for about 5
 218→//	robots, that's not real likely.
 219→#define	MATCEN_LIFE (i2f(30-2*Difficulty_level))
 220→
 221→//------------------------------------------------------------
 222→//	Trigger (enable) the materialization center in segment segnum
 223→void trigger_matcen(int segnum)
 224→{
 225→	// -- segment		*segp = &Segments[segnum];
 226→	segment2* seg2p = &Segment2s[segnum];
 227→	vms_vector	pos, delta;
 228→	FuelCenter* robotcen;
 229→	int			objnum;
 230→
 231→	mprintf((0, "Trigger matcen, segment %i\n", segnum));
 232→
 233→	Assert(seg2p->special == SEGMENT_IS_ROBOTMAKER);
 234→	Assert(seg2p->matcen_num < Num_fuelcenters);
 235→	Assert((seg2p->matcen_num >= 0) && (seg2p->matcen_num <= Highest_segment_index));
 236→
 237→	robotcen = &Station[RobotCenters[seg2p->matcen_num].fuelcen_num];
 238→
 239→	if (robotcen->Enabled == 1)
 240→		return;
 241→
 242→	if (!robotcen->Lives)
 243→		return;
 244→
 245→	//	MK: 11/18/95, At insane, matcens work forever!
 246→	if (Difficulty_level + 1 < NDL)
 247→		robotcen->Lives--;
 248→
 249→	robotcen->Timer = F1_0 * 1000;	//	Make sure the first robot gets emitted right away.
 250→	robotcen->Enabled = 1;			//	Say this center is enabled, it can create robots.
 251→	robotcen->Capacity = i2f(Difficulty_level + 3);
 252→	robotcen->Disable_time = MATCEN_LIFE;
 253→
 254→	//	Create a bright object in the segment.
 255→	pos = robotcen->Center;
 256→	vm_vec_sub(&delta, &Vertices[Segments[segnum].verts[0]], &robotcen->Center);
 257→	vm_vec_scale_add2(&pos, &delta, F1_0 / 2);
 258→	objnum = obj_create(OBJ_LIGHT, 0, segnum, &pos, NULL, 0, CT_LIGHT, MT_NONE, RT_NONE);
 259→	if (objnum != -1) {
 260→		Objects[objnum].lifeleft = MATCEN_LIFE;
 261→		Objects[objnum].ctype.light_info.intensity = i2f(8);	//	Light cast by a fuelcen.
 262→	}
 263→	else {
 264→		mprintf((1, "Can't create invisible flare for matcen.\n"));
 265→		Int3();
 266→	}
 267→	//	mprintf((0, "Created invisibile flare, object=%i, segment=%i, pos=%7.3f %7.3f%7.3f\n", objnum, segnum, f2fl(pos.x), f2fl(pos.y), f2fl(pos.z)));
 268→}
