 270→#ifdef EDITOR
 271→//------------------------------------------------------------
 272→// Takes away a segment's fuel center properties.
 273→//	Deletes the segment point entry in the FuelCenter list.
 274→void fuelcen_delete(segment* segp)
 275→{
 276→	segment2* seg2p = &Segment2s[segp - Segments];
 277→	int i, j;
 278→
 279→Restart:;
 280→
 281→	seg2p->special = 0;
 282→
 283→	for (i = 0; i < Num_fuelcenters; i++) {
 284→		if (Station[i].segnum == segp - Segments) {
 285→
 286→			// If Robot maker is deleted, fix Segments and RobotCenters.
 287→			if (Station[i].Type == SEGMENT_IS_ROBOTMAKER) {
 288→				Num_robot_centers--;
 289→				Assert(Num_robot_centers >= 0);
 290→
 291→				for (j = seg2p->matcen_num; j < Num_robot_centers; j++)
 292→					RobotCenters[j] = RobotCenters[j + 1];
 293→
 294→				for (j = 0; j < Num_fuelcenters; j++) {
 295→					if (Station[j].Type == SEGMENT_IS_ROBOTMAKER)
 296→						if (Segment2s[Station[j].segnum].matcen_num > seg2p->matcen_num)
 297→							Segment2s[Station[j].segnum].matcen_num--;
 298→				}
 299→			}
 300→
 301→			//fix RobotCenters so they point to correct fuelcenter
 302→			for (j = 0; j < Num_robot_centers; j++)
 303→				if (RobotCenters[j].fuelcen_num > i)		//this robotcenter's fuelcen is changing
 304→					RobotCenters[j].fuelcen_num--;
 305→
 306→			Num_fuelcenters--;
 307→			Assert(Num_fuelcenters >= 0);
 308→			for (j = i; j < Num_fuelcenters; j++) {
 309→				Station[j] = Station[j + 1];
 310→				Segment2s[Station[j].segnum].value = j;
 311→			}
 312→			goto Restart;
 313→		}
 314→	}
 315→
 316→}
 317→#endif
