 321→object* create_morph_robot(segment* segp, vms_vector* object_pos, int object_id)
 322→{
 323→	short		objnum;
 324→	object* obj;
 325→	int		default_behavior;
 326→
 327→	Players[Player_num].num_robots_level++;
 328→	Players[Player_num].num_robots_total++;
 329→
 330→	objnum = obj_create(OBJ_ROBOT, object_id, segp - Segments, object_pos,
 331→		&vmd_identity_matrix, Polygon_models[Robot_info[object_id].model_num].rad,
 332→		CT_AI, MT_PHYSICS, RT_POLYOBJ);
 333→
 334→	if (objnum < 0) {
 335→		mprintf((1, "Can't create morph robot.  Aborting morph.\n"));
 336→		Int3();
 337→		return NULL;
 338→	}
 339→
 340→	obj = &Objects[objnum];
 341→
 342→	//Set polygon-object-specific data 
 343→
 344→	obj->rtype.pobj_info.model_num = Robot_info[obj->id].model_num;
 345→	obj->rtype.pobj_info.subobj_flags = 0;
 346→
 347→	//set Physics info
 348→
 349→	obj->mtype.phys_info.mass = Robot_info[obj->id].mass;
 350→	obj->mtype.phys_info.drag = Robot_info[obj->id].drag;
 351→
 352→	obj->mtype.phys_info.flags |= (PF_LEVELLING);
 353→
 354→	obj->shields = Robot_info[obj->id].strength;
 355→
 356→	default_behavior = Robot_info[obj->id].behavior;
 357→
 358→	init_ai_object(obj - Objects, default_behavior, -1);		//	Note, -1 = segment this robot goes to to hide, should probably be something useful
 359→
 360→	create_n_segment_path(obj, 6, -1);		//	Create a 6 segment path from creation point.
 361→
 362→	Ai_local_info[objnum].mode = ai_behavior_to_mode(default_behavior);
 363→
 364→	return obj;
 365→}
