 396→	// mprintf((0, "Capacity of robot maker #%i is %i\n", robotcen - Station, robotcen->Capacity));
 397→
 398→	//	No robot making in multiplayer mode.
 399→#ifdef NETWORK
 400→#ifndef SHAREWARE
 401→	if ((Game_mode & GM_MULTI) && (!(Game_mode & GM_MULTI_ROBOTS) || !network_i_am_master()))
 402→		return;
 403→#else
 404→	if (Game_mode & GM_MULTI)
 405→		return;
 406→#endif
 407→#endif
 408→
 409→	// Wait until transmorgafier has capacity to make a robot...
 410→	if (robotcen->Capacity <= 0)
 411→	{
 412→		return;
 413→	}
 414→
 415→	matcen_num = Segment2s[robotcen->segnum].matcen_num;
 416→	//mprintf((0, "Robotmaker #%i flags = %8x\n", matcen_num, RobotCenters[matcen_num].robot_flags));
 417→
 418→	if (matcen_num == -1)
 419→	{
 420→		mprintf((0, "Non-functional robotcen at %d\n", robotcen->segnum));
 421→		return;
 422→	}
 423→
 424→	if (RobotCenters[matcen_num].robot_flags[0] == 0 && RobotCenters[matcen_num].robot_flags[1] == 0) {
 425→		//mprintf((0, "robot_flags = 0 at robot maker #%i\n", RobotCenters[matcen_num].robot_flags));
 426→		return;
 427→	}
 428→
 429→	// Wait until we have a free slot for this puppy...
 430→   //	  <<<<<<<<<<<<<<<< Num robots in mine >>>>>>>>>>>>>>>>>>>>>>>>>>    <<<<<<<<<<<< Max robots in mine >>>>>>>>>>>>>>>
 431→	if ((Players[Player_num].num_robots_level - Players[Player_num].num_kills_level) >= (Gamesave_num_org_robots + Num_extry_robots)) {
 432→#ifndef NDEBUG
 433→		if (FrameCount > FrameCount_last_msg + 20)
 434→		{
 435→			mprintf((0, "Cannot morph until you kill one!\n"));
 436→			FrameCount_last_msg = FrameCount;
 437→		}
 438→#endif
 439→		return;
 440→	}
 441→
 442→	robotcen->Timer += FrameTime;
 443→
 444→	switch (robotcen->Flag)
 445→	{
 446→	case 0:		// Wait until next robot can generate
 447→		if (Game_mode & GM_MULTI)
 448→		{
 449→			top_time = ROBOT_GEN_TIME;
 450→		}
 451→		else
 452→		{
 453→			dist_to_player = vm_vec_dist_quick(&ConsoleObject->pos, &robotcen->Center);
 454→			top_time = dist_to_player / 64 + P_Rand() * 2 + F1_0 * 2;
 455→			if (top_time > ROBOT_GEN_TIME)
 456→				top_time = ROBOT_GEN_TIME + P_Rand();
 457→			if (top_time < F1_0 * 2)
 458→				top_time = F1_0 * 3 / 2 + P_Rand() * 2;
 459→		}
 460→
 461→		// mprintf( (0, "Time between morphs %d seconds, dist_to_player = %7.3f\n", f2i(top_time), f2fl(dist_to_player) ));
 462→
 463→		if (robotcen->Timer > top_time)
 464→		{
 465→			int	count = 0;
 466→			int	i, my_station_num = robotcen - Station;
 467→			object* obj;
 468→
 469→			//	Make sure this robotmaker hasn't put out its max without having any of them killed.
 470→			for (i = 0; i <= Highest_object_index; i++)
 471→				if (Objects[i].type == OBJ_ROBOT)
 472→					//[ISB] This weird cast is needed due to oddness with type promotion in Watcom C. Types don't promote to the larger type of the literal as specified in the C/C++ specs,
 473→					//messing this calculation up. Thanks Arne for pointing this out. 
 474→					if ((int8_t)(Objects[i].matcen_creator ^ 0x80) == my_station_num)
 475→						count++;
 476→			if (count > Difficulty_level + 3) 
 477→			{
 478→				mprintf((0, "Cannot morph: center %i has already put out %i robots.\n", my_station_num, count));
 479→				robotcen->Timer /= 2;
 480→				return;
 481→			}
 482→
 483→			//	Whack on any robot or player in the matcen segment.
 484→			count = 0;
 485→			segnum = robotcen->segnum;
 486→			for (objnum = Segments[segnum].objects; objnum != -1; objnum = Objects[objnum].next)
 487→			{
 488→				count++;
 489→				if (count > MAX_OBJECTS)
 490→				{
 491→					mprintf((0, "Object list in segment %d is circular.", segnum));
 492→					Int3();
 493→					return;
 494→				}
 495→				if (Objects[objnum].type == OBJ_ROBOT)
 496→				{
 497→					collide_robot_and_materialization_center(&Objects[objnum]);
 498→					robotcen->Timer = top_time / 2;
 499→					return;
 500→				}
 501→				else if (Objects[objnum].type == OBJ_PLAYER)
 502→				{
 503→					collide_player_and_materialization_center(&Objects[objnum]);
 504→					robotcen->Timer = top_time / 2;
 505→					return;
 506→				}
 507→			}
 508→
 509→			compute_segment_center(&cur_object_loc, &Segments[robotcen->segnum]);
 510→			// HACK!!! The 10 under here should be something equal to the 1/2 the size of the segment.
 511→			obj = object_create_explosion(robotcen->segnum, &cur_object_loc, i2f(10), VCLIP_MORPHING_ROBOT);
 512→
 513→			if (obj)
 514→				extract_orient_from_segment(&obj->orient, &Segments[robotcen->segnum]);
 515→
 516→			if (Vclip[VCLIP_MORPHING_ROBOT].sound_num > -1)
 517→			{
 518→				digi_link_sound_to_pos(Vclip[VCLIP_MORPHING_ROBOT].sound_num, robotcen->segnum, 0, &cur_object_loc, 0, F1_0);
 519→			}
 520→			robotcen->Flag = 1;
 521→			robotcen->Timer = 0;
 522→
 523→		}
 524→		break;
 525→	case 1:			// Wait until 1/2 second after VCLIP started.
 526→		if (robotcen->Timer > (Vclip[VCLIP_MORPHING_ROBOT].play_time / 2)) {
 527→
 528→			robotcen->Capacity -= EnergyToCreateOneRobot;
 529→			robotcen->Flag = 0;
 530→
 531→			robotcen->Timer = 0;
 532→			compute_segment_center(&cur_object_loc, &Segments[robotcen->segnum]);
 533→
 534→			// If this is the first materialization, set to valid robot.
 535→			if (RobotCenters[matcen_num].robot_flags[0] != 0 || RobotCenters[matcen_num].robot_flags[1] != 0) {
 536→				int	type;
 537→				uint32_t flags;
 538→				int8_t legal_types[64];		//	64 bits, the width of robot_flags[].
 539→				int	num_types, robot_index, i;
 540→
 541→				num_types = 0;
 542→				for (i = 0; i < 2; i++) {
 543→					robot_index = i * 32;
 544→					flags = RobotCenters[matcen_num].robot_flags[i];
 545→					while (flags) {
 546→						if (flags & 1)
 547→							legal_types[num_types++] = robot_index;
 548→						flags >>= 1;
 549→						robot_index++;
 550→					}
 551→				}
 552→
 553→				//mprintf((0, "Flags = %08x, %2i legal types to morph: \n", RobotCenters[matcen_num].robot_flags, num_types));
 554→				//for (i=0; i<num_types; i++)
 555→				//	mprintf((0, "%2i ", legal_types[i]));
 556→				//mprintf((0, "\n"));
 557→
 558→				if (num_types == 1)
 559→					type = legal_types[0];
 560→				else
 561→					type = legal_types[(P_Rand() * num_types) / 32768];
 562→
 563→				mprintf((0, "Morph: (type = %i) (seg = %i) (capacity = %08x)\n", type, robotcen->segnum, robotcen->Capacity));
 564→				obj = create_morph_robot(&Segments[robotcen->segnum], &cur_object_loc, type);
 565→				if (obj != NULL) {
 566→#ifndef SHAREWARE
 567→#ifdef NETWORK
 568→					if (Game_mode & GM_MULTI)
 569→						multi_send_create_robot(robotcen - Station, obj - Objects, type);
 570→#endif
 571→#endif
 572→					obj->matcen_creator = robotcen - Station | 0x80;
 573→
 574→					// Make object faces player...
 575→					vm_vec_sub(&direction, &ConsoleObject->pos, &obj->pos);
 576→					vm_vector_2_matrix(&obj->orient, &direction, &obj->orient.uvec, NULL);
 577→
 578→					morph_start(obj);
 579→					//robotcen->last_created_obj = obj;
 580→					//robotcen->last_created_sig = robotcen->last_created_obj->signature;
 581→				}
 582→				else
 583→					mprintf((0, "Warning: create_morph_robot returned NULL (no objects left?)\n"));
 584→
 585→			}
 586→
 587→		}
 588→		break;
 589→	default:
 590→		robotcen->Flag = 0;
 591→		robotcen->Timer = 0;
 592→	}
 593→}
