 875→//--repair-- int refuel_do_repair_effect( object * obj, int first_time, int repair_seg )	{
 876→//--repair-- 
 877→//--repair-- 	obj->mtype.phys_info.velocity.x = 0;				
 878→//--repair-- 	obj->mtype.phys_info.velocity.y = 0;				
 879→//--repair-- 	obj->mtype.phys_info.velocity.z = 0;				
 880→//--repair-- 
 881→//--repair-- 	if (first_time)	{
 882→//--repair-- 		int entry_side;
 883→//--repair-- 		current_time = 0;
 884→//--repair-- 
 885→//--repair-- 		digi_play_sample( SOUND_REPAIR_STATION_PLAYER_ENTERING, F1_0 );
 886→//--repair-- 
 887→//--repair-- 		entry_side = john_find_connect_side(repair_seg,obj->segnum );
 888→//--repair-- 		Assert( entry_side > -1 );
 889→//--repair-- 
 890→//--repair-- 		switch( entry_side )	{
 891→//--repair-- 		case WBACK: sidelist = SideOrderBack; break;
 892→//--repair-- 		case WFRONT: sidelist = SideOrderFront; break;
 893→//--repair-- 		case WLEFT: sidelist = SideOrderLeft; break;
 894→//--repair-- 		case WRIGHT: sidelist = SideOrderRight; break;
 895→//--repair-- 		case WTOP: sidelist = SideOrderTop; break;
 896→//--repair-- 		case WBOTTOM: sidelist = SideOrderBottom; break;
 897→//--repair-- 		}
 898→//--repair-- 		side_index = 0;
 899→//--repair-- 		next_side = sidelist[side_index];
 900→//--repair-- 
 901→//--repair-- 		refuel_calc_deltas(obj,next_side, repair_seg);
 902→//--repair-- 	} 
 903→//--repair-- 
 904→//--repair-- 	//update shields
 905→//--repair-- 	if (Players[Player_num].shields < MAX_SHIELDS) {	//if above max, don't mess with it
 906→//--repair-- 
 907→//--repair-- 		Players[Player_num].shields += fixmul(FrameTime,repair_rate);
 908→//--repair-- 
 909→//--repair-- 		if (Players[Player_num].shields > MAX_SHIELDS)
 910→//--repair-- 			Players[Player_num].shields = MAX_SHIELDS;
 911→//--repair-- 	}
 912→//--repair-- 
 913→//--repair-- 	current_time += FrameTime;
 914→//--repair-- 
 915→//--repair-- 	if (current_time >= delta_time )	{
 916→//--repair-- 		vms_angvec av;
 917→//--repair-- 		obj->pos = goal_pos;
 918→//--repair-- 		av	= goal_angles;
 919→//--repair-- 		vm_angles_2_matrix(&obj->orient,&av);
 920→//--repair-- 
 921→//--repair-- 		if (side_index >= 5 )	
 922→//--repair-- 			return 1;		// Done being repaired...
 923→//--repair-- 
 924→//--repair-- 		if (Repairing==0)		{
 925→//--repair-- 			//mprintf( (0, "<MACHINE EFFECT ON SIDE %d>\n", next_side ));
 926→//--repair-- 			//digi_play_sample( SOUND_REPAIR_STATION_FIXING );
 927→//--repair-- 			Repairing=1;
 928→//--repair-- 
 929→//--repair-- 			switch( next_side )	{
 930→//--repair-- 			case 0:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_1,F1_0 ); break;
 931→//--repair-- 			case 1:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_2,F1_0 ); break;
 932→//--repair-- 			case 2:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_3,F1_0 ); break;
 933→//--repair-- 			case 3:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_4,F1_0 ); break;
 934→//--repair-- 			case 4:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_1,F1_0 ); break;
 935→//--repair-- 			case 5:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_2,F1_0 ); break;
 936→//--repair-- 			}
 937→//--repair-- 		
 938→//--repair-- 			repair_ship_damage();
 939→//--repair-- 
 940→//--repair-- 		}
 941→//--repair-- 
 942→//--repair-- 		if (current_time >= (delta_time+(F1_0/2)) )	{
 943→//--repair-- 			current_time = 0;
 944→//--repair-- 			// Find next side...
 945→//--repair-- 			side_index++;
 946→//--repair-- 			if (side_index >= 6 ) return 1;
 947→//--repair-- 			next_side = sidelist[side_index];
 948→//--repair-- 	
 949→//--repair-- 			refuel_calc_deltas(obj, next_side, repair_seg);
 950→//--repair-- 		}
 951→//--repair-- 
 952→//--repair-- 	} else {
 953→//--repair-- 		fix factor, p,b,h;	
 954→//--repair-- 		vms_angvec av;
 955→//--repair-- 
 956→//--repair-- 		factor = fixdiv( current_time,delta_time );
 957→//--repair-- 
 958→//--repair-- 		// Find object's current position
 959→//--repair-- 		obj->pos = delta_pos;
 960→//--repair-- 		vm_vec_scale( &obj->pos, factor );
 961→//--repair-- 		vm_vec_add2( &obj->pos, &start_pos );
 962→//--repair-- 			
 963→//--repair-- 		// Find object's current orientation
 964→//--repair-- 		p	= fixmul(delta_angles.p,factor);
 965→//--repair-- 		b	= fixmul(delta_angles.b,factor);
 966→//--repair-- 		h	= fixmul(delta_angles.h,factor);
 967→//--repair-- 		av.p = (fixang)p + start_angles.p;
 968→//--repair-- 		av.b = (fixang)b + start_angles.b;
 969→//--repair-- 		av.h = (fixang)h + start_angles.h;
 970→//--repair-- 		vm_angles_2_matrix(&obj->orient,&av);
 971→//--repair-- 
 972→//--repair-- 	}
 973→//--repair-- 
 974→//--repair-- 	update_object_seg(obj);		//update segment
 975→//--repair-- 
 976→//--repair-- 	return 0;
 977→//--repair-- }
