 125→	case SEGMENT_IS_FUELCEN:
 126→	case SEGMENT_IS_REPAIRCEN:
 127→	case SEGMENT_IS_CONTROLCEN:
 128→	case SEGMENT_IS_ROBOTMAKER:
 129→		break;
 130→	default:
 131→		Error("Invalid station type %d in fuelcen.c\n", station_type);
 132→	}
 133→
 134→	Assert((segp != NULL));
 135→	if (segp == NULL) return;
 136→
 137→	Assert(Num_fuelcenters < MAX_NUM_FUELCENS);
 138→	Assert(Num_fuelcenters > -1);
 139→
 140→	segp->value = Num_fuelcenters;
 141→	Station[Num_fuelcenters].Type = station_type;
 142→	Station[Num_fuelcenters].MaxCapacity = Fuelcen_max_amount;
 143→	Station[Num_fuelcenters].Capacity = Station[Num_fuelcenters].MaxCapacity;
 144→	Station[Num_fuelcenters].segnum = segp - Segments;
 145→	Station[Num_fuelcenters].Timer = -1;
 146→	Station[Num_fuelcenters].Flag = 0;
