 149→	//	Station[Num_fuelcenters].last_created_sig = -1;
 150→	compute_segment_center(&Station[Num_fuelcenters].Center, segp);
 151→
 152→	//	if (station_type == SEGMENT_IS_ROBOTMAKER)
 153→	//		Station[Num_fuelcenters].Capacity = i2f(Difficulty_level + 3);
 154→
 155→		//mprintf( (0, "Segment %d is assigned to be fuel center %d.\n", Station[Num_fuelcenters].segnum, Num_fuelcenters ));
 156→	Num_fuelcenters++;
 157→}
