 160→// Adds a matcen that already is a special type into the Station array.
 161→// This function is separate from other fuelcens because we don't want values reset.
 162→void matcen_create(segment* segp)
 163→{
 164→	int	station_type = segp->special;
 165→
 166→	Assert((segp != NULL));
 167→	Assert(station_type == SEGMENT_IS_ROBOTMAKER);
 168→	if (segp == NULL) return;
 169→
 170→	Assert(Num_fuelcenters < MAX_NUM_FUELCENS);
 171→	Assert(Num_fuelcenters > -1);
 172→
 173→	segp->value = Num_fuelcenters;
 174→	Station[Num_fuelcenters].Type = station_type;
 175→	Station[Num_fuelcenters].Capacity = i2f(Difficulty_level + 3);
 176→	Station[Num_fuelcenters].MaxCapacity = Station[Num_fuelcenters].Capacity;
 177→
 178→	Station[Num_fuelcenters].segnum = segp - Segments;
 179→	Station[Num_fuelcenters].Timer = -1;
 180→	Station[Num_fuelcenters].Flag = 0;
 181→	//	Station[Num_fuelcenters].NextRobotType = -1;
 182→	//	Station[Num_fuelcenters].last_created_obj=NULL;
 183→	//	Station[Num_fuelcenters].last_created_sig = -1;
 184→	compute_segment_center(&Station[Num_fuelcenters].Center, segp);
 185→
 186→	segp->matcen_num = Num_robot_centers;
 187→	Num_robot_centers++;
 188→
 189→	RobotCenters[segp->matcen_num].hit_points = MATCEN_HP_DEFAULT;
 190→	RobotCenters[segp->matcen_num].interval = MATCEN_INTERVAL_DEFAULT;
 191→	RobotCenters[segp->matcen_num].segnum = segp - Segments;
 192→	RobotCenters[segp->matcen_num].fuelcen_num = Num_fuelcenters;
 193→
 194→	//mprintf( (0, "Segment %d is assigned to be fuel center %d.\n", Station[Num_fuelcenters].segnum, Num_fuelcenters ));
 195→	Num_fuelcenters++;
 196→}
