 211→//	The lower this number is, the more quickly the center can be re-triggered.
 212→//	If it's too low, it can mean all the robots won't be put out, but for about 5
 213→//	robots, that's not real likely.
 214→#define	MATCEN_LIFE (i2f(30-2*Difficulty_level))
