 216→//------------------------------------------------------------
 217→//	Trigger (enable) the materialization center in segment segnum
 218→void trigger_matcen(int segnum)
 219→{
 220→	segment* segp = &Segments[segnum];
 221→	vms_vector	pos, delta;
 222→	FuelCenter* robotcen;
 223→	int			objnum;
 224→
 225→	mprintf((0, "Trigger matcen, segment %i\n", segnum));
 226→
 227→	Assert(segp->special == SEGMENT_IS_ROBOTMAKER);
 228→	Assert(segp->matcen_num < Num_fuelcenters);
 229→	Assert((segp->matcen_num >= 0) && (segp->matcen_num <= Highest_segment_index));
 230→
 231→	robotcen = &Station[RobotCenters[segp->matcen_num].fuelcen_num];
 232→
 233→	if (robotcen->Enabled == 1)
 234→		return;
 235→
 236→	if (!robotcen->Lives)
 237→		return;
 238→
 239→	robotcen->Lives--;
 240→	robotcen->Timer = F1_0 * 1000;	//	Make sure the first robot gets emitted right away.
 241→	robotcen->Enabled = 1;			//	Say this center is enabled, it can create robots.
 242→	robotcen->Capacity = i2f(Difficulty_level + 3);
 243→	robotcen->Disable_time = MATCEN_LIFE;
 244→
 245→	//	Create a bright object in the segment.
 246→	pos = robotcen->Center;
 247→	vm_vec_sub(&delta, &Vertices[Segments[segnum].verts[0]], &robotcen->Center);
 248→	vm_vec_scale_add2(&pos, &delta, F1_0 / 2);
 249→	objnum = obj_create(OBJ_LIGHT, 0, segnum, &pos, NULL, 0, CT_LIGHT, MT_NONE, RT_NONE);
 250→	if (objnum != -1) 
 251→	{
 252→		Objects[objnum].lifeleft = MATCEN_LIFE;
 253→		Objects[objnum].ctype.light_info.intensity = i2f(8);	//	Light cast by a fuelcen.
 254→	}
 255→	else 
 256→	{
 257→		mprintf((1, "Can't create invisible flare for matcen.\n"));
 258→		Int3();
 259→	}
 260→	//	mprintf((0, "Created invisibile flare, object=%i, segment=%i, pos=%7.3f %7.3f%7.3f\n", objnum, segnum, f2fl(pos.x), f2fl(pos.y), f2fl(pos.z)));
 261→}
