 361→//	----------------------------------------------------------------------------------------------------------
 362→void robotmaker_proc(FuelCenter* robotcen)
 363→{
 364→	fix		dist_to_player;
 365→	vms_vector	cur_object_loc; //, direction;
 366→	int		matcen_num, segnum, objnum;
 367→	object* obj;
 368→	fix		top_time;
 369→	vms_vector	direction;
 370→
 371→	if (robotcen->Enabled == 0)
 372→		return;
 373→
 374→	if (robotcen->Disable_time > 0) 
 375→	{
 376→		robotcen->Disable_time -= FrameTime;
 377→		if (robotcen->Disable_time <= 0) 
 378→		{
 379→			mprintf((0, "Robot center #%i gets disabled due to time running out.\n", robotcen - Station));
 380→			robotcen->Enabled = 0;
 381→		}
 382→	}
 383→
 384→	// mprintf((0, "Capacity of robot maker #%i is %i\n", robotcen - Station, robotcen->Capacity));
 385→
 386→	//	No robot making in multiplayer mode.
 387→#ifdef NETWORK
 388→#ifndef SHAREWARE
 389→	if ((Game_mode & GM_MULTI) && (!(Game_mode & GM_MULTI_ROBOTS) || !network_i_am_master()))
 390→		return;
 391→#else
 392→	if (Game_mode & GM_MULTI)
 393→		return;
 394→#endif
 395→#endif
 396→
 397→	// Wait until transmorgafier has capacity to make a robot...
 398→	if (robotcen->Capacity <= 0) 
 399→	{
 400→		return;
 401→	}
 402→
 403→	matcen_num = Segments[robotcen->segnum].matcen_num;
 404→	//mprintf((0, "Robotmaker #%i flags = %8x\n", matcen_num, RobotCenters[matcen_num].robot_flags));
 405→
 406→	if (matcen_num == -1) 
 407→	{
 408→		mprintf((0, "Non-functional robotcen at %d\n", robotcen->segnum));
 409→		return;
 410→	}
 411→
 412→	if (RobotCenters[matcen_num].robot_flags == 0) 
 413→	{
 414→		//mprintf((0, "robot_flags = 0 at robot maker #%i\n", RobotCenters[matcen_num].robot_flags));
 415→		return;
 416→	}
 417→
 418→	// Wait until we have a free slot for this puppy...
 419→   //	  <<<<<<<<<<<<<<<< Num robots in mine >>>>>>>>>>>>>>>>>>>>>>>>>>    <<<<<<<<<<<< Max robots in mine >>>>>>>>>>>>>>>
 420→	if ((Players[Player_num].num_robots_level - Players[Player_num].num_kills_level) >= (Gamesave_num_org_robots + Num_extry_robots)) 
 421→	{
 422→#ifndef NDEBUG
 423→		if (FrameCount > FrameCount_last_msg + 20) 
 424→		{
 425→			mprintf((0, "Cannot morph until you kill one!\n"));
 426→			FrameCount_last_msg = FrameCount;
 427→		}
 428→#endif
 429→		return;
 430→	}
 431→
 432→	robotcen->Timer += FrameTime;
 433→
 434→	switch (robotcen->Flag) 
 435→	{
 436→	case 0:		// Wait until next robot can generate
 437→		if (Game_mode & GM_MULTI)
 438→		{
 439→			top_time = ROBOT_GEN_TIME;
 440→		}
 441→		else
 442→		{
 443→			dist_to_player = vm_vec_dist_quick(&ConsoleObject->pos, &robotcen->Center);
 444→			top_time = dist_to_player / 64 + P_Rand() * 2 + F1_0 * 2;
 445→			if (top_time > ROBOT_GEN_TIME)
 446→				top_time = ROBOT_GEN_TIME + P_Rand();
 447→			if (top_time < F1_0 * 2)
 448→				top_time = F1_0 * 3 / 2 + P_Rand() * 2;
 449→		}
 450→
 451→		// mprintf( (0, "Time between morphs %d seconds, dist_to_player = %7.3f\n", f2i(top_time), f2fl(dist_to_player) ));
 452→
 453→		if (robotcen->Timer > top_time) 
 454→		{
 455→			int	count = 0;
 456→			int	i, my_station_num = robotcen - Station;
 457→			object* obj;
 458→
 459→			//	Make sure this robotmaker hasn't put out its max without having any of them killed.
 460→			for (i = 0; i <= Highest_object_index; i++)
 461→				if (Objects[i].type == OBJ_ROBOT)
 462→					//[ISB] This weird cast is needed due to oddness with type promotion in Watcom C. Types don't promote to the larger type of the literal as specified in the C/C++ specs,
 463→					//messing this calculation up. Thanks Arne for pointing this out. 
 464→					if ((int8_t)(Objects[i].matcen_creator ^ 0x80) == my_station_num) 
 465→						count++;
 466→			if (count > Difficulty_level + 3) 
 467→			{
 468→				mprintf((0, "Cannot morph: center %i has already put out %i robots.\n", my_station_num, count));
 469→				robotcen->Timer /= 2;
 470→				return;
 471→			}
 472→
 473→			//	Whack on any robot or player in the matcen segment.
 474→			count = 0;
 475→			segnum = robotcen->segnum;
 476→			for (objnum = Segments[segnum].objects; objnum != -1; objnum = Objects[objnum].next) 
 477→			{
 478→				count++;
 479→				if (count > MAX_OBJECTS)
 480→				{
 481→					mprintf((0, "Object list in segment %d is circular.", segnum));
 482→					Int3();
 483→					return;
 484→				}
 485→				if (Objects[objnum].type == OBJ_ROBOT)
 486→				{
 487→					collide_robot_and_materialization_center(&Objects[objnum]);
 488→					robotcen->Timer = top_time / 2;
 489→					return;
 490→				}
 491→				else if (Objects[objnum].type == OBJ_PLAYER)
 492→				{
 493→					collide_player_and_materialization_center(&Objects[objnum]);
 494→					robotcen->Timer = top_time / 2;
 495→					return;
 496→				}
 497→			}
 498→
 499→			compute_segment_center(&cur_object_loc, &Segments[robotcen->segnum]);
 500→			// HACK!!! The 10 under here should be something equal to the 1/2 the size of the segment.
 501→			obj = object_create_explosion(robotcen->segnum, &cur_object_loc, i2f(10), VCLIP_MORPHING_ROBOT);
 502→
 503→			if (obj)
 504→				extract_orient_from_segment(&obj->orient, &Segments[robotcen->segnum]);
 505→
 506→			if (Vclip[VCLIP_MORPHING_ROBOT].sound_num > -1) 
 507→			{
 508→				digi_link_sound_to_pos(Vclip[VCLIP_MORPHING_ROBOT].sound_num, robotcen->segnum, 0, &cur_object_loc, 0, F1_0);
 509→			}
 510→			robotcen->Flag = 1;
 511→			robotcen->Timer = 0;
 512→
 513→		}
 514→		break;
 515→	case 1:			// Wait until 1/2 second after VCLIP started.
 516→		if (robotcen->Timer > (Vclip[VCLIP_MORPHING_ROBOT].play_time / 2)) 
 517→		{
 518→
 519→			robotcen->Capacity -= EnergyToCreateOneRobot;
 520→			robotcen->Flag = 0;
 521→
 522→			robotcen->Timer = 0;
 523→			compute_segment_center(&cur_object_loc, &Segments[robotcen->segnum]);
 524→
 525→			// If this is the first materialization, set to valid robot.
 526→			if (RobotCenters[matcen_num].robot_flags != 0)
 527→			{
 528→				int	type;
 529→				uint32_t	flags;
 530→				int8_t	legal_types[32];		//	32 bits in a word, the width of robot_flags.
 531→				int	num_types, robot_index;
 532→
 533→				robot_index = 0;
 534→				num_types = 0;
 535→				flags = RobotCenters[matcen_num].robot_flags;
 536→				while (flags)
 537→				{
 538→					if (flags & 1)
 539→						legal_types[num_types++] = robot_index;
 540→					flags >>= 1;
 541→					robot_index++;
 542→				}
 543→
 544→				//mprintf((0, "Flags = %08x, %2i legal types to morph: \n", RobotCenters[matcen_num].robot_flags, num_types));
 545→				//for (i=0; i<num_types; i++)
 546→				//	mprintf((0, "%2i ", legal_types[i]));
 547→				//mprintf((0, "\n"));
 548→
 549→				if (num_types == 1)
 550→					type = legal_types[0];
 551→				else
 552→					type = legal_types[(P_Rand() * num_types) / 32768];
 553→
 554→				mprintf((0, "Morph: (type = %i) (seg = %i) (capacity = %08x)\n", type, robotcen->segnum, robotcen->Capacity));
 555→				obj = create_morph_robot(&Segments[robotcen->segnum], &cur_object_loc, type);
 556→				if (obj != NULL)
 557→				{
 558→#ifndef SHAREWARE
 559→#ifdef NETWORK
 560→					if (Game_mode & GM_MULTI)
 561→						multi_send_create_robot(robotcen - Station, obj - Objects, type);
 562→#endif
 563→#endif
 564→					obj->matcen_creator = robotcen - Station | 0x80;
 565→
 566→					// Make object faces player...
 567→					vm_vec_sub(&direction, &ConsoleObject->pos, &obj->pos);
 568→					vm_vector_2_matrix(&obj->orient, &direction, &obj->orient.uvec, NULL);
 569→
 570→					morph_start(obj);
 571→					//robotcen->last_created_obj = obj;
 572→					//robotcen->last_created_sig = robotcen->last_created_obj->signature;
 573→				}
 574→				else
 575→					mprintf((0, "Warning: create_morph_robot returned NULL (no objects left?)\n"));
 576→
 577→			}
 578→
 579→		}
 580→		break;
 581→	default:
 582→		robotcen->Flag = 0;
 583→		robotcen->Timer = 0;
 584→	}
 585→}
