 592→void controlcen_proc(FuelCenter * controlcen)
 593→{
 594→	fix old_time;
 595→	int	fc;
 596→
 597→	//	mprintf( (0, "CCT: %.1f\n", f2fl(controlcen->Timer)));
 598→
 599→	if (!Fuelcen_control_center_destroyed)	return;
 600→
 601→	//	Control center destroyed, rock the player's ship.
 602→	fc = Fuelcen_seconds_left;
 603→	if (fc > 16)
 604→		fc = 16;
 605→	ConsoleObject->mtype.phys_info.rotvel.x += fixmul(P_Rand() - 16384, 3 * F1_0 / 16 + (F1_0 * (16 - fc)) / 32);
 606→	ConsoleObject->mtype.phys_info.rotvel.z += fixmul(P_Rand() - 16384, 3 * F1_0 / 16 + (F1_0 * (16 - fc)) / 32);
 607→	//	Hook in the rumble sound effect here.
 608→
 609→	old_time = controlcen->Timer;
 610→	controlcen->Timer += RealFrameTime;			//timer_get_approx_seconds
 611→	Fuelcen_seconds_left = DIFF_CONTROL_CENTER_EXPLOSION_TIME - f2i(controlcen->Timer);
 612→	if ((old_time < COUNTDOWN_VOICE_TIME) && (controlcen->Timer >= COUNTDOWN_VOICE_TIME)) 
 613→	{
 614→		digi_play_sample(SOUND_COUNTDOWN_13_SECS, F3_0);
 615→	}
 616→	if (f2i(old_time) != f2i(controlcen->Timer)) 
 617→	{
 618→		if ((Fuelcen_seconds_left >= 0) && (Fuelcen_seconds_left < 10))
 619→			digi_play_sample(SOUND_COUNTDOWN_0_SECS + Fuelcen_seconds_left, F3_0);
 620→		if (Fuelcen_seconds_left == DIFF_CONTROL_CENTER_EXPLOSION_TIME - 1)
 621→			digi_play_sample(SOUND_COUNTDOWN_29_SECS, F3_0);
 622→	}
 623→
 624→	if (controlcen->Timer < i2f(DIFF_CONTROL_CENTER_EXPLOSION_TIME))
 625→	{
 626→		vms_vector vp;	//,v,c;
 627→		fix size;
 628→		compute_segment_center(&vp, &Segments[controlcen->segnum]);
 629→		size = (0x50000 * f2i(controlcen->Timer) * (FrameTime & 0xF)) / 16;
 630→		size = controlcen->Timer / (fl2f(0.65));
 631→		old_time = old_time / (fl2f(0.65));
 632→		if (size != old_time && (controlcen->Timer > (5 * F1_0))) {			// Every 2 seconds!
 633→			//@@object_create_explosion( controlcen->segnum, &vp, size*10, FrameTime & 7);
 634→			object_create_explosion(controlcen->segnum, &vp, size * 10, VCLIP_SMALL_EXPLOSION);
 635→			digi_play_sample(SOUND_CONTROL_CENTER_WARNING_SIREN, F3_0);
 636→		}
 637→	}
 638→	else 
 639→	{
 640→		int flash_value;
 641→
 642→		if (old_time < i2f(DIFF_CONTROL_CENTER_EXPLOSION_TIME))
 643→			digi_play_sample(SOUND_MINE_BLEW_UP, F1_0);
 644→
 645→		flash_value = f2i((controlcen->Timer - i2f(DIFF_CONTROL_CENTER_EXPLOSION_TIME)) * (64 / 4));	// 4 seconds to total whiteness
 646→		PALETTE_FLASH_SET(flash_value, flash_value, flash_value);
 647→
 648→		//gauge_message( "YOU'RE TOO SLOW! THE MINE BLEW UP!" );
 649→		if (PaletteBlueAdd > 64)
 650→		{
 651→			gr_set_current_canvas(NULL);
 652→			gr_clear_canvas(BM_XRGB(31, 31, 31));		//make screen all white to match palette effect
 653→			reset_cockpit();								//force cockpit redraw next time
 654→			reset_palette_add();							//restore palette for death message
 655→			controlcen->Timer = -1;
 656→			controlcen->MaxCapacity = Fuelcen_max_amount;
 657→			//gauge_message( "Control Center Reset" );
 658→			DoPlayerDead();		//kill_player();
 659→		}
 660→	}
 661→}
