 665→//-------------------------------------------------------------
 666→// Called once per frame, replenishes fuel supply.
 667→void fuelcen_update_all()
 668→{
 669→	int i;
 670→	fix AmountToreplenish;
 671→
 672→	AmountToreplenish = fixmul(FrameTime, Fuelcen_refill_speed);
 673→
 674→	for (i = 0; i < Num_fuelcenters; i++)
 675→	{
 676→		if (Station[i].Type == SEGMENT_IS_ROBOTMAKER) 
 677→		{
 678→			if (!(Game_suspended & SUSP_ROBOTS))
 679→				robotmaker_proc(&Station[i]);
 680→		}
 681→		else if (Station[i].Type == SEGMENT_IS_CONTROLCEN) 
 682→		{
 683→			controlcen_proc(&Station[i]);
 684→
 685→		}
