 876→//	----------------------------------------------------------------------------------------------------------
 877→void refuel_calc_deltas(object *obj, int next_side, int repair_seg)
 878→{
 879→	vms_vector nextcenter, headfvec, *headuvec;
 880→	vms_matrix goal_orient;
 881→
 882→	// Find time for this movement
 883→	delta_time = F1_0;		// one second...
 884→		
 885→	// Find start and goal position
 886→	start_pos = obj->pos;
 887→	
 888→	// Find delta position to get to goal position
 889→	compute_segment_center(&goal_pos,&Segments[repair_seg]);
 890→	vm_vec_sub( &delta_pos,&goal_pos,&start_pos);
 891→	
 892→	// Find start angles
 893→	//angles_from_vector(&start_angles,&obj->orient.fvec);
 894→	vm_extract_angles_matrix(&start_angles,&obj->orient);
 895→	
 896→	// Find delta angles to get to goal orientation
 897→	compute_center_point_on_side(&nextcenter,&Segments[repair_seg],next_side);
 898→	vm_vec_sub(&headfvec,&nextcenter,&goal_pos);
 899→	//mprintf( (0, "Next_side = %d, Head fvec = %d,%d,%d\n", next_side, headfvec.x, headfvec.y, headfvec.z ));
 900→
 901→	if (next_side == 5)						//last side
 902→		headuvec = &repair_save_uvec;
 903→	else
 904→		headuvec = &Segments[repair_seg].sides[SideUpVector[next_side]].normals[0];
 905→
 906→	vm_vector_2_matrix(&goal_orient,&headfvec,headuvec,NULL);
 907→	vm_extract_angles_matrix(&goal_angles,&goal_orient);
 908→	delta_angles.p = my_delta_ang(start_angles.p,goal_angles.p);
 909→	delta_angles.b = my_delta_ang(start_angles.b,goal_angles.b);
 910→	delta_angles.h = my_delta_ang(start_angles.h,goal_angles.h);
 911→	current_time = 0;
 912→	Repairing = 0;
 913→}
