 934→//	----------------------------------------------------------------------------------------------------------
 935→int refuel_do_repair_effect( object * obj, int first_time, int repair_seg )	{
 936→
 937→	obj->mtype.phys_info.velocity.x = 0;				
 938→	obj->mtype.phys_info.velocity.y = 0;				
 939→	obj->mtype.phys_info.velocity.z = 0;				
 940→
 941→	if (first_time)	{
 942→		int entry_side;
 943→		current_time = 0;
 944→
 945→		//digi_play_sample( SOUND_REPAIR_STATION_PLAYER_ENTERING, F1_0 );
 946→
 947→		entry_side = john_find_connect_side(repair_seg,obj->segnum );
 948→		Assert( entry_side > -1 );
 949→
 950→		switch( entry_side )	{
 951→		case WBACK: sidelist = SideOrderBack; break;
 952→		case WFRONT: sidelist = SideOrderFront; break;
 953→		case WLEFT: sidelist = SideOrderLeft; break;
 954→		case WRIGHT: sidelist = SideOrderRight; break;
 955→		case WTOP: sidelist = SideOrderTop; break;
 956→		case WBOTTOM: sidelist = SideOrderBottom; break;
 957→		}
 958→		side_index = 0;
 959→		next_side = sidelist[side_index];
 960→
 961→		refuel_calc_deltas(obj,next_side, repair_seg);
 962→	} 
 963→
 964→	//update shields
 965→	if (Players[Player_num].shields < MAX_SHIELDS) {	//if above max, don't mess with it
 966→
 967→		Players[Player_num].shields += fixmul(FrameTime,repair_rate);
 968→
 969→		if (Players[Player_num].shields > MAX_SHIELDS)
 970→			Players[Player_num].shields = MAX_SHIELDS;
 971→	}
 972→
 973→	current_time += FrameTime;
 974→
 975→	if (current_time >= delta_time )	{
 976→		vms_angvec av;
 977→		obj->pos = goal_pos;
 978→		av	= goal_angles;
 979→		vm_angles_2_matrix(&obj->orient,&av);
 980→
 981→		if (side_index >= 5 )	
 982→			return 1;		// Done being repaired...
 983→
 984→		if (Repairing==0)		{
 985→			//mprintf( (0, "<MACHINE EFFECT ON SIDE %d>\n", next_side ));
 986→			//digi_play_sample( SOUND_REPAIR_STATION_FIXING );
 987→			Repairing=1;
 988→
 989→			/*switch( next_side )	
 990→			{
 991→			case 0:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_1,F1_0 ); break;
 992→			case 1:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_2,F1_0 ); break;
 993→			case 2:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_3,F1_0 ); break;
 994→			case 3:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_4,F1_0 ); break;
 995→			case 4:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_1,F1_0 ); break;
 996→			case 5:	digi_play_sample( SOUND_REPAIR_STATION_FIXING_2,F1_0 ); break;
 997→			}*/
 998→		
 999→			repair_ship_damage();
1000→
1001→		}
1002→
1003→		if (current_time >= (delta_time+(F1_0/2)) )	{
1004→			current_time = 0;
1005→			// Find next side...
1006→			side_index++;
1007→			if (side_index >= 6 ) return 1;
1008→			next_side = sidelist[side_index];
1009→	
1010→			refuel_calc_deltas(obj, next_side, repair_seg);
1011→		}
1012→
1013→	} else {
1014→		fix factor, p,b,h;	
1015→		vms_angvec av;
1016→
1017→		factor = fixdiv( current_time,delta_time );
1018→
1019→		// Find object's current position
1020→		obj->pos = delta_pos;
1021→		vm_vec_scale( &obj->pos, factor );
1022→		vm_vec_add2( &obj->pos, &start_pos );
1023→			
1024→		// Find object's current orientation
1025→		p	= fixmul(delta_angles.p,factor);
1026→		b	= fixmul(delta_angles.b,factor);
1027→		h	= fixmul(delta_angles.h,factor);
1028→		av.p = (fixang)p + start_angles.p;
1029→		av.b = (fixang)b + start_angles.b;
1030→		av.h = (fixang)h + start_angles.h;
1031→		vm_angles_2_matrix(&obj->orient,&av);
1032→
1033→	}
1034→
1035→	update_object_seg(obj);		//update segment
1036→
1037→	return 0;
1038→}
