    CAMLlocal1(v_result);

    int objnum = Long_val(v_objnum);
    int32_t out[3] = {0, 0, 0};
    if (g_effect_gs_fetch_bash_to_shield_data)
        g_effect_gs_fetch_bash_to_shield_data(objnum, out);

    v_result = caml_alloc(3, 0);
