CAMLprim value cd_ox_effect_gs_write_bash_to_shield(value v_packed)
{
    CAMLparam1(v_packed);

    if (g_effect_gs_write_bash_to_shield) {
        int len = Wosize_val(v_packed);
        int32_t buf[8];
        if (len > 8) len = 8;
        for (int i = 0; i < len; i++)
            buf[i] = (int32_t)Long_val(Field(v_packed, i));
