int john_find_connect_side(int seg0,int seg1)
{
	segment *Seg=&Segments[seg0];
	int i;

 	for (i=MAX_SIDES_PER_SEGMENT;i--;) if (Seg->children[i]==seg1) return i;

 	return -1;
 }

